        int rightPtr = nums.length - 1;

        while (leftPtr <= rightPtr) {

            int midPtr = leftPtr + (rightPtr - leftPtr) / 2;

            if (nums[midPtr] == target)
                return midPtr;

            if (nums[midPtr] < target) leftPtr = midPtr + 1;
