package string.recursive;

import java.util.HashSet;
import java.util.List;
import java.util.Set;

public class WordBreak {

    public boolean wordBreak(String s, List<String> wordDict) {
        return dfs(s, 0, new HashSet<>(wordDict), new Boolean[s.length()]);
    }

    private boolean dfs(String s, int start, Set<String> wordDict, Boolean[] memo) {

        if (start >= s.length())
            return true;

        if (memo[start] != null)
            return memo[start];

        for (int end = start; end < s.length(); end++) {
            var word = s.substring(start, end + 1);
            if (wordDict.contains(word) && dfs(s, end + 1, wordDict, memo))
                return memo[start] = true;
        }

        return memo[start] = false;
    }

}

package graph.iterative;

import java.util.*;

public class WordLadder {

    public int ladderLength(String beginWord, String endWord, List<String> wordList) {

        wordList.add(beginWord);
        Map<String, List<String>> graph = getGraph(wordList);
        Queue<String> queue             = new ArrayDeque<>(List.of(beginWord));
        Set<String> visited             = new HashSet<>(queue);

        int ladderLength = 1;
        while (!queue.isEmpty()) {
            int n = queue.size();
            for (int i = 0; i < n; i++) {
                var word = queue.remove();

                if (word.equals(endWord))
                    return ladderLength;

                graph.get(word)
                        .stream()
                        .filter(visited::add)
                        .forEach(queue::add);
            }
            ladderLength++;
        }

        return 0;
    }

    private Map<String, List<String>> getGraph(List<String> wordList) {
        int n = wordList.size();
        Map<String, List<String>> graph = new HashMap<>(n);

        for (int i = 0; i < n; i++) {
            var a = wordList.get(i);
            var neighsA = graph.computeIfAbsent(a, any -> new ArrayList<>());

            for (int j = i; j < n; j++) {
                var b = wordList.get(j);
                var neighsB = graph.computeIfAbsent(b, any -> new ArrayList<>());
                if (!isNeigh(a, b)) continue;
                neighsA.add(b);
                neighsB.add(a);
            }
        }

        return graph;
    }

    private boolean isNeigh(String a, String b) {
        int n = a.length(), countDiff = 0;
        for (int i = 0; i < n; i++) {
            if (a.charAt(i) != b.charAt(i)) countDiff++;
            if (countDiff > 1)              return false;
        }

        return true;
    }

}
